typedef struct Node {
    int starting;
    int no_of_edges;
} Node;

__kernel void BFS_1(__global Node *x_0,
                    __global int *g_graph_edges,
                    __global char *g_graph_mask,
                    __global char *elem_1,
                    __global char *v_3,
                    __global int *g_cost,
                    int tmp_2)
{
    int tid = (int)get_global_id(0);

    if (tid < tmp_2 && g_graph_mask[tid]) {
        g_graph_mask[tid] = 0;
        for (int i = x_0[tid].starting;
             i < (x_0[tid].starting + x_0[tid].no_of_edges);
             i++) {
            int v_4 = g_graph_edges[i];
            if (!v_3[v_4]) {
                g_cost[v_4] = g_cost[tid] + 1;
                elem_1[v_4] = 1;
            }
        }
    }
}

__kernel void BFS_2(__global char *g_graph_mask,
                    __global char *g_updating_graph_mask,
                    __global char *g_graph_visited,
                    __global char *g_over,
                    int no_of_nodes)
{
    int tid = (int)get_global_id(0);

    if (tid < no_of_nodes && g_updating_graph_mask[tid]) {
        g_graph_mask[tid] = 1;
        g_graph_visited[tid] = 1;
        *g_over = 1;
        g_updating_graph_mask[tid] = 0;
    }
}
